mapper.update:
UPDATE TAB_STOCK
SET I_QTY = I_QTY + #{qty},
    DT_UPDATE_TIME = NOW(),
    S_UPDATE_USER = #{operator}
WHERE S_GOODS_ID = #{goodsId} AND S_WAREHOUSE_ID = #{warehouseId}

UPDATE TAB_STOCK
SET I_QTY = I_QTY - #{qty},
    DT_UPDATE_TIME = NOW(),
    S_UPDATE_USER = #{operator}
WHERE S_GOODS_ID = #{goodsId}
  AND S_WAREHOUSE_ID = #{warehouseId}
  AND I_QTY >= #{qty}

UPDATE TAB_STOCK
SET I_QTY = I_QTY + #{changeQty},
    DT_UPDATE_TIME = NOW(),
    S_UPDATE_USER = #{operator}
WHERE S_GOODS_ID = #{goodsId} AND S_WAREHOUSE_ID = #{warehouseId}
